#include<bits/stdc++.h>
using namespace std;
vector<int> mp[1010],mp1[1010];
bool instk[1010];
stack<int> s;
int n,m;
int f[1010][1010];
int dfn[1010],w[1010],W[1010],v[1010],V[1010],id[1010],low[1010],siz[1010],dfncnt,scccnt;
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    s.push(x);
    instk[x]=true;
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            s.pop();
            id[top]=scccnt;
            siz[scccnt]++;
            W[scccnt]+=w[top];
            V[scccnt]+=v[top];
            instk[top]=false;
        }while(top!=x);
    }
}
void dfs(int x)
{
    for(int i=W[x];i<=m;i++)
    {
        f[x][i]=V[x];
    }
    for(int i:mp1[x])
    {
        dfs(i);
        for(int j=m-W[x];j>=1;j--)
        {
            for(int k=0;k<=j;k++)
            {
                f[x][j+W[x]]=max(f[x][j+W[x]],f[i][k]+f[x][j+W[x]-k]);
            }
        }
    }
}
int in[1010];
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&w[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&v[i]);
    }
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        if(x!=0)
        {
            mp[x].push_back(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j:mp[i])
        {
            if(id[i]!=id[j])
            {
                mp1[id[i]].push_back(id[j]);
                in[id[j]]++;
            }
        }
    }
    for(int i=1;i<=scccnt;i++)
    {
        if(!in[i])
        {
            mp1[0].push_back(i);
        }
    }
    dfs(0);
    printf("%d",f[0][m]);
    return 0;
}
